parseOptions.snippet:
function parseOptions(args = []) {
    const options = {
        savefile: null,
        compact: false,
        exclude: []
    };

    for (let i = 0; i < args.length; i++) {
        const arg = args[i];

        if (arg === "--savefile") {
            options.savefile =
                args[i + 1] || null;

            i++;
            continue;
        }

        if (arg === "--compact") {
            options.compact = true;
            continue;
        }

        if (arg === "--exclude") {
            const value =
                args[i + 1] || "";

            options.exclude =
                value
                    .split(",")
                    .map(v =>
                        v.trim()
                    )
                    .filter(Boolean);

            i++;
            continue;
        }
    }

    return options;
}

