normalizeFilePaths.snippet:
function normalizeFilePaths(
    value,
    root
) {
    if (
        Array.isArray(value)
    ) {
        value.forEach(item =>
            normalizeFilePaths(
                item,
                root
            )
        );

        return;
    }

    if (
        !value ||
        typeof value !==
            "object"
    ) {
        return;
    }

    if (
        typeof value.file ===
        "string"
    ) {
        try {
            value.file =
                path.relative(
                    root,
                    value.file
                );
        } catch {}
    }

    for (const key of Object.keys(
        value
    )) {
        normalizeFilePaths(
            value[key],
            root
        );
    }
}

