function buildStatistics(files) {
    const stats = {
        files: files.length,
        javascript: 0,
        typescript: 0,
        jsx: 0,
        tsx: 0,
        json: 0,
        markdown: 0,
        other: 0
    };

    for (const file of files) {
        const ext =
            path.extname(file);

        switch (ext) {
            case ".js":
                stats.javascript++;
                break;

            case ".ts":
                stats.typescript++;
                break;

            case ".jsx":
                stats.jsx++;
                break;

            case ".tsx":
                stats.tsx++;
                break;

            case ".json":
                stats.json++;
                break;

            case ".md":
                stats.markdown++;
                break;

            default:
                stats.other++;
                break;
        }
    }

    return stats;
}

