function analyzeFiles(files) {
    const parsedFiles = [];

    const analysis = {
        imports: [],
        exports: [],
        functions: [],
        classes: [],
        interfaces: [],
        types: [],
        enums: [],
        components: [],
        hooks: [],
        props: [],
        routes: []
    };

    for (const file of files) {
        const ext =
            path.extname(file);

        try {
            let result = null;

            if (ext === ".js") {
                result =
                    parseJavaScript(
                        file
                    );
            }

            else if (
                ext === ".ts"
            ) {
                result =
                    parseTypeScript(
                        file
                    );
            }

            else if (
                ext === ".jsx" ||
                ext === ".tsx"
            ) {
                result =
                    parseReact(
                        file
                    );
            }

            if (!result) {
                continue;
            }

            parsedFiles.push(
                result
            );

            for (const key of Object.keys(
                analysis
            )) {
                if (
                    result[key]
                ) {
                    analysis[key].push(
                        ...result[key]
                    );
                }
            }
        } catch {}
    }

    return {
        parsedFiles,
        analysis
    };
}

