                    "anonymous",

                async:
                    path.node
                        .async,

                generator:
                    path.node
                        .generator,

                params:
                    path.node
                        .params
                        .length,

                type:
                    "declaration",

                startLine:
                    start,

                endLine:
                    end,

                snippet:
                    getSnippet(
                        lines,
