walkFiles.snippet:
function walkFiles(dir, files = []) {
    const entries = fs.readdirSync(dir, {
        withFileTypes: true
    });

    for (const entry of entries) {
        const fullPath = path.join(dir, entry.name);

        if (shouldIgnore(entry.name)) {
            continue;
        }

        if (entry.isDirectory()) {
            walkFiles(fullPath, files);
            continue;
        }

        files.push(fullPath);
    }

    return files;
}

