function detectArchitecture(
    parsedFiles
) {
    const layers =
        detectLayers(
            parsedFiles
        );

    const patterns =
        detectPatterns(
            parsedFiles,
            layers
        );

    return {
        layers,
        patterns
    };
}

function detectLayers(parsedFiles) {
    const layers = {
        controllers: [],
        services: [],
        models: [],
        repositories: [],
        middleware: [],
        routes: [],
        components: [],
        utilities: []
    };

    for (const file of parsedFiles) {
        const lower =
            file.file.toLowerCase();

        if (
            lower.includes(
                "controller"
            )
        ) {
            layers.controllers.push(
                file.file
            );
        }

        if (
            lower.includes(
                "service"
            )
        ) {
            layers.services.push(
                file.file
            );
        }

        if (
            lower.includes(
                "model"
            )
        ) {
            layers.models.push(
                file.file
            );
        }

        if (
            lower.includes(
                "repository"
            )
        ) {
            layers.repositories.push(
                file.file
            );
        }

        if (
            lower.includes(
                "middleware"
            )
        ) {
            layers.middleware.push(
                file.file
            );
        }

        if (
            lower.includes(
                "route"
            )
        ) {
            layers.routes.push(
                file.file
            );
        }

        if (
            file.components &&
            file.components.length
        ) {
            layers.components.push(
                file.file
            );
        }

        if (
            lower.includes(
                "util"
            ) ||
            lower.includes(
                "helper"
            )
        ) {
            layers.utilities.push(
                file.file
            );
        }
    }

    return layers;
}

function detectPatterns(
    parsedFiles,
    layers
) {
    const patterns = [];

    if (
        layers.controllers.length &&
        layers.services.length &&
        layers.models.length
    ) {
        patterns.push("mvc");
    }

    if (
        layers.services.length &&
        layers.repositories.length
    ) {
        patterns.push(
            "service-repository"
        );
    }

    const hasReact =
        parsedFiles.some(
            file =>
                file.components &&
                file.components.length
        );

    if (hasReact) {
        patterns.push(
            "component-based"
        );
    }

    return patterns;
}

function detectAuth(
