    }

    console.log(output);

    return result;
}

function buildGraph(parsedFiles) {
    const dependencyGraph =
        buildDependencyGraph(
            parsedFiles
        );

    const callGraphs = [];

    const componentGraphs = [];

    for (const file of parsedFiles) {
        try {
            const source =
                fs.readFileSync(
                    file.file,
                    "utf8"
                );

            const ast =
                createAST(source);

            callGraphs.push(
                buildCallGraph(
                    ast,
                    file.file
                )
            );

            componentGraphs.push({
                file: file.file,
                graph:
                    buildComponentGraph(
                        ast
                    )
            });
        } catch {}
    }

    return buildKnowledgeGraph({
    dependencyGraph,
    callGraphs,
    componentGraphs,
    parsedFiles
});
}

function buildCallGraph(ast, file) {
    const graph = {};

    traverse(ast, {
        FunctionDeclaration(path) {
            const functionName =
                path.node.id?.name;

            if (!functionName) {
                return;
            }

            graph[functionName] = [];

            path.traverse({
                CallExpression(callPath) {
                    const callee =
                        callPath.node.callee;

                    if (
                        callee.type ===
                        "Identifier"
                    ) {
                        graph[
                            functionName
                        ].push(
                            callee.name
                        );
                    }
                }
            });
        }
    });

    return {
        file,
        graph
    };
}

function buildComponentGraph(ast) {
    const graph = {};

    let currentComponent = null;

    traverse(ast, {
        FunctionDeclaration(path) {
            const name =
                path.node.id?.name;

            if (
                !name ||
                name[0] !==
                    name[0].toUpperCase()
            ) {
                return;
            }

            currentComponent = name;

            graph[currentComponent] =
                [];
        },

        JSXElement(path) {
            if (!currentComponent) {
                return;
            }

            const tag =
                path.node.openingElement
                    ?.name?.name;

            if (!tag) {
                return;
            }

            if (
                tag[0] ===
                tag[0].toUpperCase()
            ) {
                graph[
                    currentComponent
                ].push(tag);
            }
        }
    });

    return graph;
}

function buildDependencyGraph(parsedFiles) {
    const graph = {};

    for (const file of parsedFiles) {
        graph[file.file] = [];

        if (!file.imports) {
            continue;
        }

        for (const dependency of file.imports) {
            graph[file.file].push(
                dependency.source
            );
        }
    }

    return graph;
}

function buildKnowledgeGraph({
    dependencyGraph,
    callGraphs,
    componentGraphs,
    parsedFiles = []
}) {
    const graph = {
        generatedAt:
            new Date().toISOString(),

        nodes: [],

        edges: [],

        dependencyGraph,

        callGraphs,

        componentGraphs
    };

    for (const file of parsedFiles) {
        graph.nodes.push({
            type: "file",
            name: file.file
        });

        for (const item of file.imports || []) {
            graph.edges.push({
                type: "imports",
                from: file.file,
                to: item.source
            });
        }

        for (const item of file.functions || []) {
            graph.nodes.push({
                type: "function",
                name: item.name,
                file: file.file
            });

            graph.edges.push({
                type: "contains",
                from: file.file,
                to: item.name
            });
        }

        for (const item of file.classes || []) {
            graph.nodes.push({
                type: "class",
                name: item.name,
                file: file.file
            });

            graph.edges.push({
                type: "contains",
                from: file.file,
                to: item.name
            });
        }

        for (const item of file.components || []) {
            graph.nodes.push({
                type: "component",
                name: item.name,
                file: file.file
            });

            graph.edges.push({
                type: "contains",
                from: file.file,
                to: item.name
            });
        }

        for (const item of file.interfaces || []) {
            graph.nodes.push({
                type: "interface",
                name: item.name,
                file: file.file
            });

            graph.edges.push({
                type: "contains",
                from: file.file,
                to: item.name
            });
        }

        for (const item of file.enums || []) {
            graph.nodes.push({
                type: "enum",
                name: item.name,
                file: file.file
            });

            graph.edges.push({
                type: "contains",
                from: file.file,
                to: item.name
            });
        }
    }

    return graph;
}

