function tokenize(text) {
    return String(text || "")
        .toLowerCase()
        .replace(/[^a-z0-9\s]/g, " ")
        .split(/\s+/)
        .filter(Boolean);
}

function createEmbedding(text) {
    const tokens =
        tokenize(text);

    const vector = {};

    for (const token of tokens) {
        vector[token] =
            (vector[token] || 0) + 1;
    }

    return vector;
}

function similarity(a, b) {
    let dot = 0;

    let magA = 0;

    let magB = 0;

    const keys =
        new Set([
            ...Object.keys(a),
            ...Object.keys(b)
        ]);

    for (const key of keys) {
        const x = a[key] || 0;
        const y = b[key] || 0;

        dot += x * y;

        magA += x * x;

        magB += y * y;
    }

    if (!magA || !magB) {
        return 0;
    }

    return (
        dot /
        (Math.sqrt(magA) *
            Math.sqrt(magB))
    );
}

function queryEngine(
    project,
    question
) {
    const q =
        String(question)
            .toLowerCase();

    if (
        q.includes(
            "framework"
        )
    ) {
        return {
            type:
                "frameworks",

            answer:
                project.frameworks
        };
    }

    if (
        q.includes(
            "feature"
        )
    ) {
        return {
            type:
                "features",

            answer:
                project
                    .analyzers
                    ?.features ||
                []
        };
    }

    if (
        q.includes(
            "route"
        )
    ) {
        return {
            type:
                "routes",

            answer:
                project
                    .analyzers
                    ?.routes ||
                []
        };
    }

    if (
        q.includes(
            "architecture"
        )
    ) {
        return {
            type:
                "architecture",

            answer:
                project
                    .analyzers
                    ?.architecture ||
                {}
        };
    }

    if (
        q.startsWith(
            "where is "
        )
    ) {
        const symbol =
            question
                .replace(
                    /where is/i,
                    ""
                )
                .trim();

        return {
            type:
                "symbol",

            answer:
                project
                    .symbols?.[
                    symbol
                ] || null
        };
    }

    if (
        q.startsWith(
            "show code for "
        )
    ) {
        const symbol =
            question
                .replace(
                    /show code for/i,
                    ""
                )
                .trim();

        const result =
            project
                .symbols?.[
                symbol
            ];

        return {
            type:
                "snippet",

            answer:
                result
                    ?.snippet ||
                null
        };
    }

    return {
        type:
            "search",

        answer:
            search(
                project,
                question
            )
    };
}

function search(
    project,
    query
) {
    const q =
        String(query)
            .toLowerCase();

    const results =
        [];

    const symbols =
        project.symbols ||
        {};

    for (const [
        name,
        symbol
    ] of Object.entries(
        symbols
    )) {
        const text = [
            name,
            symbol.file,
            symbol.type,
            symbol.snippet
        ]
            .filter(Boolean)
            .join(" ")
            .toLowerCase();

        if (
            text.includes(q)
        ) {
            results.push({
                score: 100,
                symbol:
                    name,
                ...symbol
            });
        }
    }

    const functions =
        project.analysis
            ?.functions ||
        [];

    for (const fn of functions) {
        const text = JSON.stringify(
            fn
        ).toLowerCase();

        if (
            text.includes(q)
        ) {
            results.push({
                score: 50,
                type:
                    "function",
                data: fn
            });
        }
    }

    const classes =
        project.analysis
            ?.classes ||
        [];

    for (const cls of classes) {
        const text = JSON.stringify(
            cls
        ).toLowerCase();

        if (
            text.includes(q)
        ) {
            results.push({
                score: 50,
                type:
                    "class",
                data: cls
            });
        }
    }

    return results.sort(
        (a, b) =>
            b.score -
            a.score
    );
}

function getSnippet(
    lines,
    start,
    end
) {
    if (
        !start ||
        !end
    ) {
        return null;
    }

    return lines
        .slice(
            start - 1,
            end
        )
        .join("\n");
}

function extractClasses(
    ast,
    lines = []
) {
    const classes = [];

    traverse(ast, {
        ClassDeclaration(
            path
        ) {
            const methods =
                [];

            for (const body of path
                .node.body
                .body) {
                if (
                    body.type !==
                    "ClassMethod"
                ) {
                    continue;
                }

                methods.push({
                    name:
                        body.key
                            ?.name,

                    async:
                        body.async,

                    static:
                        body.static
                });
            }

            const start =
                path.node.loc
                    ?.start
                    ?.line ||
                null;

            const end =
                path.node.loc
                    ?.end
                    ?.line ||
                null;

            classes.push({
                name:
                    path.node.id
                        ?.name,

                methods,

                startLine:
                    start,

                endLine:
                    end,

                snippet:
                    getSnippet(
                        lines,
                        start,
                        end
                    )
            });
        }
    });

    return classes;
}

function extractExports(ast) {
    const exports = [];

    for (const node of ast.program.body) {
        if (
            node.type === "ExportNamedDeclaration" &&
            node.declaration
        ) {
            const declaration = node.declaration;

            if (declaration.id?.name) {
                exports.push(declaration.id.name);
            }

            if (
                declaration.declarations &&
                declaration.declarations.length
            ) {
                for (const item of declaration.declarations) {
                    if (item.id?.name) {
                        exports.push(item.id.name);
                    }
                }
            }
        }

        if (node.type === "ExportDefaultDeclaration") {
            exports.push("default");
        }
    }

    return exports;
}

