function extractProps(ast) {
    const props = [];

    traverse(ast, {
        FunctionDeclaration(path) {
            const name = path.node.id?.name;

            if (!name) {
                return;
            }

            if (
                path.node.params.length > 0
            ) {
                props.push({
                    component: name,
                    params:
                        path.node.params.map(
                            param =>
                                param.name ||
                                param.type
                        )
                });
            }
        }
    });

    return props;
}

function extractRoutes(ast) {
    const routes = [];

    traverse(ast, {
        JSXElement(path) {
            const opening =
                path.node.openingElement;

            const tag =
                opening.name?.name;

            if (
                tag === "Route" ||
                tag === "Link"
            ) {
                routes.push({
                    type: tag
                });
            }
        }
    });

    return routes;
}

