function buildTree(files) {
    const tree = {};

    for (const file of files) {
        const parts = file.split(path.sep);

        let current = tree;

        for (const part of parts) {
            if (!current[part]) {
                current[part] = {};
            }

            current = current[part];
        }
    }

    return tree;
}

function readFile(file) {
    try {
        const content =
            fs.readFileSync(
                file,
                "utf8"
            );

        return {
            content,
            lines:
                content.split(
                    /\r?\n/
                )
        };
    } catch {
        return {
            content: "",
            lines: []
        };
    }
}

function shouldIgnore(name) {
    return DEFAULT_IGNORES.includes(
        name
    );
}

function walkFiles(dir, files = []) {
    const entries = fs.readdirSync(dir, {
        withFileTypes: true
    });

    for (const entry of entries) {
        const fullPath = path.join(dir, entry.name);

        if (shouldIgnore(entry.name)) {
            continue;
        }

        if (entry.isDirectory()) {
            walkFiles(fullPath, files);
            continue;
        }

        files.push(fullPath);
    }

    return files;
}

function ensureStore() {
    if (!fs.existsSync(STORE_DIR)) {
        fs.mkdirSync(STORE_DIR, {
            recursive: true
        });
    }

    if (!fs.existsSync(STORE_FILE)) {
        fs.writeFileSync(
            STORE_FILE,
            JSON.stringify(
                {
                    files: []
                },
                null,
                2
            )
        );
    }
}

function getStore() {
    ensureStore();

    try {
        return JSON.parse(
            fs.readFileSync(
                STORE_FILE,
                "utf8"
            )
        );
    } catch {
        return {
            files: []
        };
    }
}

function saveStore(data) {
    ensureStore();

    fs.writeFileSync(
        STORE_FILE,
        JSON.stringify(
            data,
            null,
            2
        )
    );
}

function registerFile(file) {
    const store =
        getStore();

    const exists =
        store.files.find(
            item =>
                item.path ===
                file.path
        );

    if (exists) {
        return false;
    }

    store.files.push(file);

    saveStore(store);

    return true;
}
